AS $function$
  SELECT '<div class="pgv-alert pgv-alert-' || p_level || '" role="alert">'
    || p_message || '</div>';
$function$;
COMMENT ON FUNCTION pgv.alert(text,text) IS 'Inline banner/callout (info/success/warning/danger) — not transient like toast';

CREATE OR REPLACE FUNCTION pgv.app_nav()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb := '[]'::jsonb;
  v_mod record;
  v_schema text;
  v_brand text;
  v_items jsonb;
BEGIN
  FOR v_mod IN
    SELECT tm.module
      FROM workbench.tenant_module tm
     WHERE tm.active = true
       AND tm.module <> 'pgv'
     ORDER BY tm.sort_order, tm.module
  LOOP
    -- Resolve schema: find the namespace that has nav_items()
    SELECT n.nspname INTO v_schema
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
     WHERE p.proname = 'nav_items'
       AND n.nspname NOT LIKE '%\_qa' ESCAPE '\'
       AND n.nspname NOT LIKE '%\_ut' ESCAPE '\'
       AND n.nspname <> 'pgv'
       AND (n.nspname = v_mod.module OR v_mod.module LIKE n.nspname || '%')
     ORDER BY
       CASE WHEN n.nspname = v_mod.module THEN 0 ELSE 1 END
     LIMIT 1;

    IF v_schema IS NULL THEN
      CONTINUE;
    END IF;

    -- Get brand
    BEGIN
      EXECUTE format('SELECT %I.brand()', v_schema) INTO v_brand;
    EXCEPTION WHEN OTHERS THEN
      v_brand := initcap(v_mod.module);
    END;

    -- Get nav_items (handle both jsonb and TABLE return)
    BEGIN
      EXECUTE format('SELECT %I.nav_items()', v_schema) INTO v_items;
    EXCEPTION WHEN OTHERS THEN
      BEGIN
        EXECUTE format(
          'SELECT jsonb_agg(jsonb_build_object(''href'', href, ''label'', label, ''icon'', icon)) FROM %I.nav_items()',
          v_schema
        ) INTO v_items;
      EXCEPTION WHEN OTHERS THEN
        v_items := '[]'::jsonb;
      END;
    END;

    v_result := v_result || jsonb_build_object(
      'module', v_mod.module,
      'brand', v_brand,
      'schema', v_schema,
      'items', coalesce(v_items, '[]'::jsonb)
    );
  END LOOP;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION pgv.app_nav() IS 'Aggregated navigation for all active tenant modules. Returns JSON array of modules with brand, schema, and nav items.';

CREATE OR REPLACE FUNCTION pgv.call_ref(p_fname text, p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_schema text;
  v_path text;
  v_qs text := '';
  v_key text;
  v_val text;
BEGIN
  -- Get current schema from route context
  v_schema := trim(LEADING '/' FROM coalesce(current_setting('pgv.route_prefix', true), ''));

  -- Verify function exists in pg_proc
  IF v_schema <> '' THEN
    IF NOT EXISTS (
      SELECT 1 FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = v_schema AND p.proname = p_fname AND p.prokind = 'f'
    ) THEN
      RAISE EXCEPTION 'pgv.call_ref: function %.% not found', v_schema, p_fname
        USING HINT = 'Check that the function exists in schema ' || v_schema;
    END IF;
  END IF;

  -- Derive path from function name: get_drawing → /drawing, get_index → /
  v_path := regexp_replace(p_fname, '^(get|post)_', '');
  IF v_path = 'index' THEN
    v_path := '/';
  ELSE
    v_path := '/' || v_path;
  END IF;

  -- Build query string from params
  FOR v_key, v_val IN SELECT k, v FROM jsonb_each_text(p_params) AS x(k, v)
  LOOP
    -- Percent-encode critical query string characters
    v_val := replace(replace(replace(replace(replace(
      v_val, '%', '%25'), '&', '%26'), '=', '%3D'), '+', '%2B'), ' ', '%20');
    IF v_qs = '' THEN
      v_qs := '?' || v_key || '=' || v_val;
    ELSE
      v_qs := v_qs || '&' || v_key || '=' || v_val;
    END IF;
  END LOOP;

  -- Build full URL with schema prefix
  IF v_schema <> '' THEN
    RETURN '/' || v_schema || v_path || v_qs;
  ELSE
    RETURN v_path || v_qs;
  END IF;
END;
$function$;
COMMENT ON FUNCTION pgv.call_ref(text,jsonb) IS 'Build a verified internal route URL from a function name + params. Checks pg_proc to detect dead links at render time.';

CREATE OR REPLACE FUNCTION pgv.card(p_title text, p_body text, p_footer text DEFAULT NULL::text, p_md boolean DEFAULT false)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
SELECT '<article>'
    || CASE WHEN p_title IS NOT NULL THEN '<header>' || p_title || '</header>' ELSE '' END
    || CASE WHEN p_md THEN '<md>' || p_body || '</md>' ELSE p_body END
    || CASE WHEN p_footer IS NOT NULL THEN '<footer>' || p_footer || '</footer>' ELSE '' END
    || '</article>';
$function$;
COMMENT ON FUNCTION pgv.card(text,text,text,boolean) IS 'Render an article card. p_md=true wraps body in <md> for markdown rendering.';

CREATE OR REPLACE FUNCTION pgv.esc(p_text text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT replace(replace(replace(replace(replace(
    coalesce(p_text, ''),
    '&', '&amp;'), '<', '&lt;'), '>', '&gt;'), '"', '&quot;'), '''', '&#39;');
$function$;

CREATE OR REPLACE FUNCTION pgv.accordion(VARIADIC p_items text[])
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_count int := array_length(p_items, 1) / 2;
  v_html text := '';
BEGIN
  FOR i IN 0..v_count-1 LOOP
    v_html := v_html || '<details class="pgv-accordion">'
      || '<summary>' || pgv.esc(p_items[i*2+1]) || '</summary>'
      || '<div>' || p_items[i*2+2] || '</div>'
      || '</details>';
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.accordion(text[]) IS 'Collapsible sections via native details/summary (VARIADIC title/content pairs)';

CREATE OR REPLACE FUNCTION pgv.action(p_rpc text, p_label text, p_params jsonb DEFAULT NULL::jsonb, p_confirm text DEFAULT NULL::text, p_variant text DEFAULT 'primary'::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<button data-rpc="' || p_rpc || '"'
    || CASE WHEN p_params IS NOT NULL THEN ' data-params=''' || p_params::text || '''' ELSE '' END
    || CASE WHEN p_confirm IS NOT NULL THEN ' data-confirm="' || pgv.esc(p_confirm) || '"' ELSE '' END
    || CASE WHEN p_variant = 'danger' THEN ' class="secondary"'
            WHEN p_variant = 'outline' THEN ' class="outline"'
            ELSE '' END
    || '>' || pgv.esc(p_label) || '</button>';
$function$;

