  SELECT '<div class="pgv-empty"><h4>' || pgv.esc(p_title) || '</h4>'
    || CASE WHEN p_detail IS NOT NULL THEN '<p>' || pgv.esc(p_detail) || '</p>' ELSE '' END
    || '</div>';
$function$;
