CREATE OR REPLACE FUNCTION pgv.doc(p_topic text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_content text;
BEGIN
  SELECT content INTO v_content FROM workbench.doc WHERE topic = p_topic;
  IF NOT FOUND THEN
    RETURN pgv.empty('Document introuvable', 'Topic: ' || pgv.esc(p_topic));
  END IF;
  RETURN '<md>' || v_content || '</md>';
END;
$function$;
COMMENT ON FUNCTION pgv.doc(text) IS 'Render a workbench.doc topic as markdown block. Returns md-wrapped content or empty state.';

CREATE OR REPLACE FUNCTION pgv.error(p_status text, p_title text, p_detail text DEFAULT NULL::text, p_hint text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_html text;
BEGIN
  v_html := '<article class="pgv-error">'
    || '<header><strong>' || pgv.esc(p_status) || E' \u2014 ' || pgv.esc(p_title) || '</strong></header>';
  IF p_detail IS NOT NULL THEN v_html := v_html || '<p>' || pgv.esc(p_detail) || '</p>'; END IF;
  IF p_hint IS NOT NULL THEN v_html := v_html || '<p><small>' || pgv.esc(p_hint) || '</small></p>'; END IF;
  v_html := v_html || '<footer><a href="#" class="pgv-error-report" onclick="'
    || 'var desc=this.closest(''.pgv-error'').textContent.trim();'
    || 'var dlg=this.closest(''dialog'');if(dlg)dlg.close();'
    || 'var d=Alpine.$data(document.querySelector(''[x-data]''));'
    || 'd.issue={open:true,desc:desc,type:''bug''};'
    || 'return false;">Signaler ce bug</a></footer>';
  v_html := v_html || '</article>';
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.error(text,text,text,text) IS 'Render error card with optional bug report button';

CREATE OR REPLACE FUNCTION pgv.filesize(p_bytes bigint)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_bytes IS NULL THEN '-'
    WHEN p_bytes < 1024 THEN p_bytes || ' B'
    WHEN p_bytes < 1048576 THEN round(p_bytes / 1024.0, 1) || ' KB'
    WHEN p_bytes < 1073741824 THEN round(p_bytes / 1048576.0, 1) || ' MB'
    ELSE round(p_bytes / 1073741824.0, 1) || ' GB'
  END;
$function$;

CREATE OR REPLACE FUNCTION pgv.grid(VARIADIC p_items text[])
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<div class="grid">' || array_to_string(p_items, '') || '</div>';
$function$;

CREATE OR REPLACE FUNCTION pgv.href(p_url text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF left(p_url, 8) = 'https://' THEN RETURN p_url; END IF;
  IF left(p_url, 7) = 'http://'  THEN RETURN p_url; END IF;
  IF left(p_url, 2) = '//'       THEN RETURN p_url; END IF;
  IF left(p_url, 7) = 'mailto:'  THEN RETURN p_url; END IF;
  IF left(p_url, 4) = 'tel:'     THEN RETURN p_url; END IF;

  RAISE EXCEPTION 'pgv.href() is for external URLs only — use pgv.call_ref() for internal links. Got: %', p_url;
END;
$function$;
COMMENT ON FUNCTION pgv.href(text) IS 'External links only. RAISEs on internal paths — use pgv.call_ref() instead.';

CREATE OR REPLACE FUNCTION pgv.html_audit(p_schema text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_rec record;
  v_rows text := '';
  v_warn int := 0;
  v_ok int := 0;
  v_rules jsonb;
BEGIN
  -- Rules: tag pattern -> primitive, with exclusion if primitive is also called
  -- excl: if present, skip match when this pattern is also found (avoids false positives)
  v_rules := '[
    {"tag":"<template data-toast",  "prim":"pgv.toast()",          "call":"pgv.toast("},
    {"tag":"<template data-redirect","prim":"pgv.redirect()",     "call":"pgv.redirect("},
    {"tag":"<form data-rpc",        "prim":"pgv.form()",          "call":"pgv.form("},
    {"tag":"<button data-rpc",      "prim":"pgv.action()",        "call":"pgv.action("},
    {"tag":"<details>",             "prim":"pgv.accordion()",     "call":"pgv.accordion("},
    {"tag":"<select>",              "prim":"pgv.sel()",           "call":"pgv.sel("},
    {"tag":"<dl>",                  "prim":"pgv.dl()",            "call":"pgv.dl("},
    {"tag":"<article",              "prim":"pgv.card()",          "call":"pgv.card("},
    {"tag":"<input ",               "prim":"pgv.input()",         "call":"pgv.input(",         "excl":"type=\\\"hidden\\\""},
    {"tag":"type=\\\"checkbox\\\"","prim":"pgv.checkbox()",     "call":"pgv.checkbox("},
    {"tag":"type=\\\"radio\\\"",   "prim":"pgv.radio()",         "call":"pgv.radio("},
    {"tag":"<textarea",             "prim":"pgv.textarea()",      "call":"pgv.textarea("},
    {"tag":"<progress",             "prim":"pgv.progress()",      "call":"pgv.progress("},
    {"tag":"<table",                "prim":"pgv.md_table()",      "call":"pgv.md_table("},
    {"tag":"pgv-alert",             "prim":"pgv.alert()",         "call":"pgv.alert("},
    {"tag":"pgv-badge",             "prim":"pgv.badge()",         "call":"pgv.badge("},
    {"tag":"pgv-stat",              "prim":"pgv.stat()",          "call":"pgv.stat("},
    {"tag":"pgv-grid",              "prim":"pgv.grid()",          "call":"pgv.grid("},
    {"tag":"pgv-tabs",              "prim":"pgv.tabs()",          "call":"pgv.tabs("},
    {"tag":"pgv-breadcrumb",        "prim":"pgv.breadcrumb()",    "call":"pgv.breadcrumb("},
    {"tag":"pgv-empty",             "prim":"pgv.empty()",         "call":"pgv.empty("},
    {"tag":"pgv-timeline",          "prim":"pgv.timeline()",      "call":"pgv.timeline("},
    {"tag":"pgv-workflow",          "prim":"pgv.workflow()",      "call":"pgv.workflow("},
    {"tag":"pgv-avatar",            "prim":"pgv.avatar()",        "call":"pgv.avatar("},
    {"tag":"selectSearch",          "prim":"pgv.select_search()", "call":"pgv.select_search("},
    {"tag":"x-data=\\\"lazy\\\"","prim":"pgv.lazy()",           "call":"pgv.lazy("}
  ]'::jsonb;

  FOR v_rec IN
    WITH fn_bodies AS (
      SELECT p.proname, p.prosrc AS def
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema
        AND (p.proname LIKE 'get_%' OR p.proname LIKE 'post_%')
    ),
    rule_checks AS (
      SELECT f.proname,
             r->>'tag' AS tag,
             r->>'prim' AS prim,
             f.def LIKE '%' || (r->>'tag') || '%' AS has_tag,
             f.def LIKE '%' || (r->>'call') || '%' AS has_call,
             CASE WHEN r->>'excl' IS NOT NULL
                  THEN f.def LIKE '%' || (r->>'excl') || '%'
                  ELSE false END AS has_excl
      FROM fn_bodies f
      CROSS JOIN jsonb_array_elements(v_rules) AS r
    )
    SELECT proname, tag, prim
    FROM rule_checks
    WHERE has_tag AND NOT has_call AND NOT has_excl
    ORDER BY proname, tag
  LOOP
    v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning')
      || ' | ' || v_rec.proname || '()'
      || ' | `' || pgv.esc(v_rec.tag) || '`'
      || ' | ' || v_rec.prim || ' |' || chr(10);
    v_warn := v_warn + 1;
  END LOOP;

  IF v_warn = 0 THEN
    v_ok := 1;
  END IF;

  RETURN pgv.dl(
    'HTML audit', p_schema,
    'Bilan',
      CASE WHEN v_warn > 0 THEN pgv.badge(v_warn || ' raw HTML', 'warning') || ' ' ELSE '' END
      || CASE WHEN v_ok > 0 THEN pgv.badge('clean', 'success') ELSE '' END)
    || '<md>' || chr(10)
    || '| Niveau | Source | Tag | Primitive |' || chr(10)
    || '|--------|--------|-----|-----------|' || chr(10)
    || v_rows
    || '</md>';
END;
$function$;
COMMENT ON FUNCTION pgv.html_audit(text) IS 'Scan schema functions for raw HTML that should use pgv.* primitives. Returns markdown report.';

