$function$;
COMMENT ON FUNCTION pgv.i18n_seed() IS 'Seed French translations for pgv framework strings into pgv.i18n table.';

CREATE OR REPLACE FUNCTION pgv.input(p_name text, p_type text, p_label text, p_value text DEFAULT NULL::text, p_required boolean DEFAULT false)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<label>' || p_label
    || CASE WHEN p_required THEN ' <sup>*</sup>' ELSE '' END
    || '<input name="' || p_name || '" type="' || p_type || '"'
    || CASE WHEN p_value IS NOT NULL THEN ' value="' || pgv.esc(p_value) || '"' ELSE '' END
    || CASE WHEN p_required THEN ' required' ELSE '' END
    || '></label>';
$function$;

CREATE OR REPLACE FUNCTION pgv.lazy(p_rpc text, p_params jsonb DEFAULT '{}'::jsonb, p_placeholder text DEFAULT 'Chargement...'::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<div class="pgv-lazy" data-lazy="' || pgv.esc(p_rpc) || '"'
    || CASE WHEN p_params <> '{}'::jsonb
         THEN ' data-params=''' || p_params::text || ''''
         ELSE '' END
    || '><p aria-busy="true">' || pgv.esc(p_placeholder) || '</p></div>';
$function$;
COMMENT ON FUNCTION pgv.lazy(text,jsonb,text) IS 'Lazy container: defers content loading via IntersectionObserver + RPC';

CREATE OR REPLACE FUNCTION pgv.link_button(p_href text, p_label text, p_variant text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
SELECT '<a href="' || pgv.esc(p_href) || '" role="button" class="pgv-link-button'
    || CASE WHEN p_variant = 'outline' THEN ' outline'
            WHEN p_variant = 'secondary' THEN ' secondary'
            WHEN p_variant = 'contrast' THEN ' contrast'
            ELSE '' END
    || '">' || pgv.esc(p_label) || '</a>';
$function$;
COMMENT ON FUNCTION pgv.link_button(text,text,text) IS 'Navigation link styled as a button, visually aligned with pgv.action(). Variants: NULL (primary), outline, secondary, contrast.';

CREATE OR REPLACE FUNCTION pgv.md_esc(p_text text, p_max_len integer DEFAULT 80)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT left(
    replace(replace(replace(pgv.esc(p_text), '|', '\|'), E'\n', ' '), E'\r', ''),
    p_max_len
  );
$function$;
COMMENT ON FUNCTION pgv.md_esc(text,integer) IS 'Escape text for safe use in markdown table cells — escapes pipes, newlines, HTML, and truncates';

CREATE OR REPLACE FUNCTION pgv.md_table(p_headers text[], p_rows text[], p_page_size integer DEFAULT 0)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_md text;
  v_sep text;
  v_ncols int;
  v_nrows int;
BEGIN
  v_ncols := array_length(p_headers, 1);
  IF p_rows IS NOT NULL AND array_length(p_rows, 1) % v_ncols <> 0 THEN
    RAISE EXCEPTION 'md_table: p_rows length % is not a multiple of % columns',
      array_length(p_rows, 1), v_ncols;
  END IF;
  v_md := '| ' || array_to_string(p_headers, ' | ') || E' |\n';
  v_sep := '|';
  FOR i IN 1..v_ncols LOOP
    v_sep := v_sep || ' --- |';
  END LOOP;
  v_md := v_md || v_sep || E'\n';
  IF p_rows IS NOT NULL AND array_length(p_rows, 1) > 0 THEN
    v_nrows := array_length(p_rows, 1) / v_ncols;
    FOR i IN 0..v_nrows - 1 LOOP
      v_md := v_md || '| ' || array_to_string(p_rows[i * v_ncols + 1 : (i + 1) * v_ncols], ' | ') || E' |\n';
    END LOOP;
  END IF;
  RETURN '<figure><md' || CASE WHEN p_page_size > 0 THEN ' data-page="' || p_page_size || '"' ELSE '' END || '>' || v_md || '</md></figure>';
END;
$function$;
COMMENT ON FUNCTION pgv.md_table(text[],text[],integer) IS 'Generate markdown table from PL/pgSQL arrays (headers + flat rows). Optional p_page_size for client-side pagination.';

CREATE OR REPLACE FUNCTION pgv.money(p_amount numeric)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT to_char(p_amount, 'FM999 999 990D00') || ' EUR';
$function$;

CREATE OR REPLACE FUNCTION pgv.nav(p_brand text, p_items jsonb, p_current text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_item jsonb;
  v_href text;
  v_label text;
  v_burger boolean := coalesce((p_options->>'burger')::boolean, false);
BEGIN
  IF v_burger THEN
    v_html := '<nav class="container-fluid pgv-nav-burger" x-data="{ open: false }">';
  ELSE
    v_html := '<nav class="container-fluid">';
  END IF;

  -- Brand + burger toggle
  v_html := v_html || '<ul><li><a href="' || pgv.call_ref('get_index') || '" class="pgv-brand"><strong>' || pgv.esc(p_brand) || '</strong></a></li>';
  IF v_burger THEN
    v_html := v_html || '<li class="pgv-burger-li">'
      || '<button class="pgv-burger" @click="open = !open" aria-label="Menu">'
      || '<span x-text="open ? ''✕'' : ''☰''">☰</span></button></li>';
  END IF;
  v_html := v_html || '</ul>';

  -- Menu links
  IF v_burger THEN
    v_html := v_html || '<ul class="pgv-menu" :class="open && ''pgv-menu-open''" @click="open = false">';
  ELSE
    v_html := v_html || '<ul>';
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP
    v_href  := v_item->>'href';
    v_label := v_item->>'label';
    IF v_href ~ '^https?://' THEN
      v_html := v_html || format('<li><a href="%s" target="_blank" rel="noopener">%s</a></li>', v_href, pgv.esc(v_label));
    ELSIF v_href = p_current THEN
      v_html := v_html || format('<li><a href="%s" aria-current="page">%s</a></li>', v_href, pgv.esc(v_label));
    ELSE
      v_html := v_html || format('<li><a href="%s">%s</a></li>', v_href, pgv.esc(v_label));
    END IF;
  END LOOP;
  v_html := v_html || '</ul>';

  -- Theme toggle
  v_html := v_html || '<ul><li>'
    || '<button class="pgv-theme-toggle" data-toggle-theme title="Changer de theme">'
    || '&#x263E;</button></li></ul></nav>';

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.nav(text,jsonb,text,jsonb) IS 'Generate nav bar HTML. Options: burger (boolean) for responsive hamburger menu.';

CREATE OR REPLACE FUNCTION pgv.page(p_brand text, p_title text, p_path text, p_nav jsonb, p_body text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN pgv.nav(p_brand, p_nav, p_path, p_options)
    || '<main class="container">'
    || '<hgroup><h2>' || pgv.esc(p_title) || '</h2></hgroup>'
    || p_body
    || '</main>';
END;
$function$;
COMMENT ON FUNCTION pgv.page(text,text,text,jsonb,text,jsonb) IS 'Wrap body in nav + main layout. Options forwarded to pgv.nav().';

CREATE OR REPLACE FUNCTION pgv.progress(p_value numeric, p_max numeric DEFAULT 100, p_label text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<div class="pgv-progress">'
    || CASE WHEN p_label IS NOT NULL
         THEN '<label>' || pgv.esc(p_label) || ' <small>' || round(p_value / p_max * 100) || '%</small></label>'
         ELSE '' END
    || '<progress value="' || p_value || '" max="' || p_max || '"></progress>'
    || '</div>';
$function$;
COMMENT ON FUNCTION pgv.progress(numeric,numeric,text) IS 'Progress bar with optional label (PicoCSS native styling)';

CREATE OR REPLACE FUNCTION pgv.radio(p_name text, p_label text, p_options jsonb, p_selected text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_html text;
  v_opt text;
BEGIN
  v_html := '<fieldset><legend>' || pgv.esc(p_label) || '</legend>';
  FOR v_opt IN SELECT jsonb_array_elements_text(p_options)
  LOOP
    v_html := v_html || '<label><input type="radio" name="' || p_name || '" value="' || pgv.esc(v_opt) || '"'
      || CASE WHEN v_opt = p_selected THEN ' checked' ELSE '' END
      || '> ' || pgv.esc(v_opt) || '</label>';
  END LOOP;
  RETURN v_html || '</fieldset>';
END;
$function$;
COMMENT ON FUNCTION pgv.radio(text,text,jsonb,text) IS 'Radio button group (PicoCSS native styling)';

CREATE OR REPLACE FUNCTION pgv.redirect(p_path text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN '<template data-redirect="' || pgv.esc(p_path) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION pgv.redirect(text) IS 'POST response: redirect via Alpine shell. Returns template tag with data-redirect.';

CREATE OR REPLACE FUNCTION pgv.route(p_schema text, p_path text, p_method text DEFAULT 'GET'::text, p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_nav jsonb;
  v_opts jsonb;
  v_brand text;
  v_title text;
  v_fname text;
  v_body text;
  v_detail text;
  v_hint text;
  v_route text;
  v_nargs int;
  v_argtype text;
  v_argname text;
BEGIN
  -- Set i18n language for this request
  PERFORM set_config('pgv.lang', coalesce(nullif(current_setting('pgv.lang', true), ''), 'fr'), true);

  -- Get nav items
  BEGIN
    EXECUTE format('SELECT %I.nav_items()', p_schema) INTO v_nav;
  EXCEPTION WHEN undefined_function THEN
    RAISE EXCEPTION 'Module % has no nav_items() function', p_schema;
  END;

  -- Get brand (optional, fallback to schema name)
  BEGIN
    EXECUTE format('SELECT %I.brand()', p_schema) INTO v_brand;
  EXCEPTION WHEN undefined_function THEN
    v_brand := initcap(p_schema);
  END;

  -- Get nav options (optional, fallback to empty)
  BEGIN
    EXECUTE format('SELECT %I.nav_options()', p_schema) INTO v_opts;
  EXCEPTION WHEN undefined_function THEN
    v_opts := '{}'::jsonb;
  END;

  -- Derive function name: method + path
  IF p_path = '/' THEN
    v_fname := lower(p_method) || '_index';
  ELSE
    v_fname := lower(p_method) || '_' || replace(replace(trim(BOTH '/' FROM p_path), '/', '_'), '-', '_');
  END IF;

  -- Full route path
  v_route := '/' || p_schema || p_path;

  -- Set route prefix early (pgv.call_ref() needs it)
  PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);

  -- Prefix nav hrefs with schema
  v_nav := (
    SELECT jsonb_agg(
      CASE WHEN (item->>'href') ~ '^https?://'
        THEN item
        ELSE jsonb_set(item, '{href}', to_jsonb('/' || p_schema || (item->>'href')))
      END
    )
    FROM jsonb_array_elements(v_nav) AS item
  );

  -- Introspect function signature (max 1 arg)
  SELECT p.pronargs,
         CASE WHEN p.pronargs > 0 THEN (p.proargtypes::oid[])[0]::regtype::text END,
         CASE WHEN p.pronargs > 0 THEN p.proargnames[1] END
  INTO v_nargs, v_argtype, v_argname
  FROM pg_proc p
  JOIN pg_namespace n ON n.oid = p.pronamespace
  WHERE n.nspname = p_schema AND p.proname = v_fname AND p.prokind = 'f'
    AND p.pronargs <= 1;

  IF NOT FOUND THEN
    -- GET: return 200 with error page (shell renders HTML, no need for HTTP error)
    -- POST: return 404 so shell shows toast via _err()
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '404', true);
      RETURN '<template data-toast="error">Page non trouvee: ' || pgv.esc(p_method || ' ' || p_path) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, '404', v_route, v_nav,
      pgv.error('404', 'Page non trouvee', 'Le chemin ' || p_method || ' ' || p_path || ' n''existe pas.'), v_opts);
  END IF;

  -- Execute based on signature
  IF v_nargs = 0 THEN
    EXECUTE format('SELECT %I.%I()', p_schema, v_fname) INTO v_body;
  ELSIF v_argtype = 'jsonb' THEN
    EXECUTE format('SELECT %I.%I($1)', p_schema, v_fname) USING p_params INTO v_body;
  ELSIF v_argtype IN ('integer', 'bigint', 'text', 'uuid') THEN
    EXECUTE format('SELECT %I.%I($1::%s)', p_schema, v_fname, v_argtype)
      USING p_params->>v_argname INTO v_body;
  ELSE
    -- Composite type: deserialize jsonb into typed record
    EXECUTE format('SELECT %I.%I(jsonb_populate_record(NULL::%s, $1))', p_schema, v_fname, v_argtype)
      USING p_params INTO v_body;
  END IF;

  -- POST: return raw (toast/redirect templates, no layout)
  IF lower(p_method) = 'post' THEN
    RETURN v_body;
  END IF;

  -- GET: find title from nav
  SELECT item->>'label' INTO v_title
  FROM jsonb_array_elements(v_nav) AS item
  WHERE item->>'href' = v_route;

  IF v_title IS NULL THEN
    v_title := initcap(replace(regexp_replace(v_fname, '^(get|post)_', ''), '_', ' '));
  END IF;

  -- Wrap in page layout
  RETURN pgv.page(v_brand, v_title, v_route, v_nav, v_body, v_opts);

EXCEPTION
  WHEN raise_exception THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT, v_hint = PG_EXCEPTION_HINT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '400', true);
      RETURN '<template data-toast="error">' || pgv.esc(v_detail) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('400', 'Erreur', v_detail, v_hint), v_opts);
  WHEN invalid_text_representation THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '400', true);
      RETURN '<template data-toast="error">' || pgv.esc(v_detail) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('400', 'Parametre invalide', v_detail), v_opts);
  WHEN OTHERS THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '500', true);
      RETURN '<template data-toast="error">Erreur interne</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('500', 'Erreur interne', 'Une erreur inattendue est survenue.'), v_opts);
END;
$function$;
COMMENT ON FUNCTION pgv.route(text,text,text,jsonb) IS 'Router: maps method+path to get_*/post_* functions via pg_proc introspection. Supports 0-arg, scalar, jsonb, and composite type parameters.';

CREATE OR REPLACE FUNCTION pgv.diagnose(p_schema text, p_path text DEFAULT '/'::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text;
  v_start timestamptz;
  v_ms numeric;
  v_rows text := '';
  v_err int := 0;
  v_warn int := 0;
  v_ok int := 0;
  v_rec record;
  v_ns text;
  v_fn text;
  v_href text;
  v_params text[];
  v_inputs text[];
  v_missing text[];
  v_pages text[];
  v_page text;
  v_path_only text;
  v_params_jsonb jsonb;
  v_reports text := '';
  v_css_ok boolean;
BEGIN
  -- If path is '*', diagnose all nav pages
  IF p_path = '*' THEN
    BEGIN
      EXECUTE format(
        'SELECT array_agg(item->>''href'') FROM jsonb_array_elements(%I.nav_items()) AS item WHERE NOT (item->>''href'') ~ ''^https?://''',
        p_schema
      ) INTO v_pages;
    EXCEPTION WHEN OTHERS THEN
      -- nav_items() may return TABLE(label, href, icon) instead of jsonb
      EXECUTE format(
        'SELECT array_agg(href) FROM %I.nav_items() WHERE NOT href ~ ''^https?://''',
        p_schema
      ) INTO v_pages;
    END;
  ELSE
    v_pages := ARRAY[p_path];
  END IF;

  FOREACH v_page IN ARRAY v_pages LOOP
    v_rows := '';
    v_err := 0; v_warn := 0; v_ok := 0;

    -- Parse query params from path
    v_params_jsonb := '{}'::jsonb;
    IF v_page LIKE '%?%' THEN
      v_path_only := split_part(v_page, '?', 1);
      FOR v_rec IN
        SELECT split_part(pair, '=', 1) AS k, split_part(pair, '=', 2) AS v
        FROM unnest(string_to_array(split_part(v_page, '?', 2), '&')) AS pair
      LOOP
        v_params_jsonb := v_params_jsonb || jsonb_build_object(v_rec.k, v_rec.v);
      END LOOP;
    ELSE
      v_path_only := v_page;
    END IF;

    -- Render page
    v_start := clock_timestamp();
    BEGIN
      v_html := pgv.route(p_schema, v_path_only, 'GET', v_params_jsonb);
    EXCEPTION WHEN OTHERS THEN
      v_reports := v_reports || pgv.error('500', p_schema || ':' || v_page, SQLERRM) || chr(10);
      CONTINUE;
    END;
    v_ms := round(extract(epoch from clock_timestamp() - v_start) * 1000, 1);

    -- 1. Inline styles
    IF v_html ~ ' style\s*=\s*"' THEN
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Style | inline `style` detecte |' || chr(10);
      v_err := v_err + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Style | aucun inline style |' || chr(10);
      v_ok := v_ok + 1;
    END IF;

    -- 2. HTMX
    IF v_html ~ '\bhx-' THEN
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | HTMX | attributs hx-* detectes |' || chr(10);
      v_err := v_err + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | HTMX | aucun |' || chr(10);
      v_ok := v_ok + 1;
    END IF;

    -- 3. Raw <table> without <md>
    IF v_html ~ '<table[\s>]' AND v_html !~ '<md' THEN
      v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | Table | `<table>` sans `<md>` |' || chr(10);
      v_warn := v_warn + 1;
    END IF;

    -- 4. data-rpc targets
    FOR v_rec IN
      SELECT DISTINCT x[1] AS rpc FROM regexp_matches(v_html, 'data-rpc="([^"]+)"', 'g') t(x)
    LOOP
      IF v_rec.rpc LIKE '%.%' THEN
        v_ns := split_part(v_rec.rpc, '.', 1);
        v_fn := split_part(v_rec.rpc, '.', 2);
      ELSE
        v_ns := p_schema;
        v_fn := v_rec.rpc;
      END IF;
      -- Shell routes POST via pgv.route(): post_ + rpc_without_post_
      v_fn := 'post_' || regexp_replace(v_fn, '^post_', '');

      IF EXISTS (
        SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
        WHERE n.nspname = v_ns AND p.proname = v_fn
      ) THEN
        v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | RPC | `' || v_ns || '.' || v_fn || '()` |' || chr(10);
        v_ok := v_ok + 1;
      ELSE
        v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | RPC | `' || v_ns || '.' || v_fn || '()` introuvable |' || chr(10);
        v_err := v_err + 1;
      END IF;
    END LOOP;

    -- 5. Internal href targets (cross-module aware)
    FOR v_rec IN
      SELECT DISTINCT x[1] AS raw_href FROM regexp_matches(v_html, 'href="(/[^"]*)"', 'g') t(x)
    LOOP
      v_href := v_rec.raw_href;
      -- Strip query params for resolution
      IF v_href LIKE '%?%' THEN v_href := split_part(v_href, '?', 1); END IF;

      -- Detect target schema from first path segment
      v_ns := split_part(trim(LEADING '/' FROM v_href), '/', 1);
      IF v_ns <> p_schema AND EXISTS (
        SELECT 1 FROM pg_namespace WHERE nspname = v_ns
      ) THEN
        -- Cross-module link: /crm/client -> crm.get_client()
        v_fn := CASE
          WHEN trim(BOTH '/' FROM substr(v_href, length(v_ns) + 2)) = '' THEN 'get_index'
          ELSE 'get_' || replace(replace(trim(BOTH '/' FROM substr(v_href, length(v_ns) + 2)), '/', '_'), '-', '_')
        END;
      ELSE
        -- Same-module link: strip schema prefix if present
        IF v_href LIKE '/' || p_schema || '/%' THEN
          v_href := substr(v_href, length(p_schema) + 2);
        ELSIF v_href = '/' || p_schema OR v_href = '/' || p_schema || '/' THEN
          v_href := '/';
        END IF;
        v_ns := p_schema;
        v_fn := CASE WHEN v_href = '/' THEN 'get_index'
                ELSE 'get_' || replace(replace(trim(BOTH '/' FROM v_href), '/', '_'), '-', '_') END;
      END IF;

      IF EXISTS (
        SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
        WHERE n.nspname = v_ns AND p.proname = v_fn
      ) THEN
        v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Lien | `' || pgv.esc(v_rec.raw_href) || '` -> `' || v_ns || '.' || v_fn || '()` |' || chr(10);
        v_ok := v_ok + 1;
      ELSE
        v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Lien | `' || pgv.esc(v_rec.raw_href) || '` -> `' || v_ns || '.' || v_fn || '()` introuvable |' || chr(10);
        v_err := v_err + 1;
      END IF;
    END LOOP;

    -- 6. <md> blocks valid
    FOR v_rec IN
      SELECT x[1] AS md_body FROM regexp_matches(v_html, '<md[^>]*>(.*?)</md>', 'g') t(x)
    LOOP
      IF v_rec.md_body ~ '^\s*\|.+\|\s*\n\s*\|[-| ]+\|' THEN
        v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Markdown | bloc `<md>` valide |' || chr(10);
        v_ok := v_ok + 1;
      ELSE
        v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Markdown | `<md>` sans header valide |' || chr(10);
        v_err := v_err + 1;
      END IF;
    END LOOP;

    -- 7. Form fields vs function signature
    FOR v_rec IN
      SELECT DISTINCT x[1] AS rpc FROM regexp_matches(v_html, '<form[^>]*data-rpc="([^"]+)"', 'g') t(x)
    LOOP
      SELECT proargnames INTO v_params
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema AND p.proname = 'post_' || regexp_replace(v_rec.rpc, '^post_', '')
      LIMIT 1;

      IF v_params IS NOT NULL THEN
        v_inputs := ARRAY(
          SELECT DISTINCT x[1] FROM regexp_matches(v_html, 'name="([^"]+)"', 'g') t(x)
        );
        v_missing := ARRAY(
          SELECT unnest(v_params) EXCEPT SELECT unnest(v_inputs)
        );
        IF array_length(v_missing, 1) > 0 THEN
          v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | Form | `' || v_rec.rpc || '()` params sans champ: ' || array_to_string(v_missing, ', ') || ' |' || chr(10);
          v_warn := v_warn + 1;
        ELSE
          v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Form | `' || v_rec.rpc || '()` signature couverte |' || chr(10);
          v_ok := v_ok + 1;
        END IF;
      END IF;
    END LOOP;

    -- 8. CSS class validation
    v_css_ok := true;
    FOR v_rec IN
      SELECT DISTINCT cls FROM (
        SELECT unnest(string_to_array(x[1], ' ')) AS cls
        FROM regexp_matches(v_html, 'class="([^"]*pgv-[^"]*)"', 'g') t(x)
      ) sub WHERE cls LIKE 'pgv-%'
    LOOP
      IF v_rec.cls NOT IN (
        'pgv-lazy','pgv-brand','pgv-burger-li','pgv-burger','pgv-nav-burger',
        'pgv-menu','pgv-menu-open',
        'pgv-badge','pgv-badge-success','pgv-badge-danger','pgv-badge-warning','pgv-badge-info','pgv-badge-primary',
        'pgv-stat','pgv-stat-value','pgv-dl','pgv-error',
        'pgv-alert','pgv-alert-success','pgv-alert-danger','pgv-alert-warning','pgv-alert-info',
        'pgv-empty','pgv-progress','pgv-avatar',
        'pgv-tabs','pgv-tabs-nav','pgv-accordion','pgv-breadcrumb',
        'pgv-tree','pgv-tree-icon','pgv-theme-toggle',
        'pgv-table','pgv-pager','pgv-pager-info','pgv-pager-btns','pgv-pager-dots',
        'pgv-sortable','pgv-canvas','pgv-canvas-vp','pgv-canvas-bar','pgv-canvas-btn','pgv-canvas-zoom','pgv-canvas-sep',
        'pgv-search-results','pgv-search-item','pgv-search-icon','pgv-search-body','pgv-search-more',
        'pgv-link-button',
        'pgv-form-dialog','pgv-form-dialog-article','pgv-form-dialog-header',
        'pgv-form-dialog-close','pgv-form-dialog-body','pgv-form-dialog-footer',
        'pgv-plugin-error',
        'pgv-filter','pgv-filter-bar','pgv-filter-inputs','pgv-filter-submit','pgv-filter-chips',
        'pgv-col-link','pgv-col-badge','pgv-col-date',
        'pgv-print-btn'
      ) THEN
        v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | CSS | classe `' || pgv.esc(v_rec.cls) || '` inconnue |' || chr(10);
        v_warn := v_warn + 1;
        v_css_ok := false;
      END IF;
    END LOOP;
    IF v_css_ok THEN
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | CSS | toutes les classes pgv-* connues |' || chr(10);
      v_ok := v_ok + 1;
    END IF;

    -- Page report
    v_reports := v_reports || pgv.dl(
      'Page', p_schema || ' : ' || v_page,
      'Rendu', v_ms || ' ms',
      'Bilan',
        CASE WHEN v_err > 0 THEN pgv.badge(v_err || ' erreur(s)', 'danger') || ' ' ELSE '' END
        || CASE WHEN v_warn > 0 THEN pgv.badge(v_warn || ' warning(s)', 'warning') || ' ' ELSE '' END
        || pgv.badge(v_ok || ' ok', 'success'))
      || '<md>' || chr(10)
      || '| Niveau | Check | Detail |' || chr(10)
      || '|--------|-------|--------|' || chr(10)
      || v_rows
      || '</md>' || chr(10);

  END LOOP;

  -- 9. Static RPC analysis (schema-wide, source code scan)
  v_rows := '';
  v_err := 0; v_ok := 0; v_warn := 0;
  FOR v_rec IN
    WITH rpc_refs AS (
      -- data-rpc="xxx" in function bodies
      SELECT p.proname AS source,
             (regexp_matches(pg_get_functiondef(p.oid), 'data-rpc="([^"]+)"', 'g'))[1] AS rpc
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema
      UNION
      -- pgv.action('xxx', ...) calls
      SELECT p.proname AS source,
             (regexp_matches(pg_get_functiondef(p.oid), E'pgv\\.action\\(''([^'']+)''', 'g'))[1] AS rpc
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema
    ),
    resolved AS (
      SELECT DISTINCT r.source, r.rpc,
             CASE WHEN r.rpc LIKE '%.%' THEN split_part(r.rpc, '.', 1) ELSE p_schema END AS target_schema,
             'post_' || regexp_replace(
               CASE WHEN r.rpc LIKE '%.%' THEN split_part(r.rpc, '.', 2) ELSE r.rpc END,
               '^post_', ''
             ) AS target_fn
      FROM rpc_refs r
    )
    SELECT r.source, r.rpc, r.target_schema, r.target_fn,
           EXISTS (
             SELECT 1 FROM pg_proc p2 JOIN pg_namespace n2 ON n2.oid = p2.pronamespace
             WHERE n2.nspname = r.target_schema AND p2.proname = r.target_fn
           ) AS found
    FROM resolved r
    ORDER BY found, r.source, r.rpc
  LOOP
    IF v_rec.found THEN
      v_ok := v_ok + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | ' || pgv.esc(v_rec.source) || ' | `' || v_rec.rpc || '` -> `' || v_rec.target_schema || '.' || v_rec.target_fn || '()` introuvable |' || chr(10);
      v_err := v_err + 1;
    END IF;
  END LOOP;

  IF v_err > 0 OR v_ok > 0 THEN
    v_reports := v_reports || pgv.dl(
      'Analyse statique RPC', p_schema,
      'Bilan',
        CASE WHEN v_err > 0 THEN pgv.badge(v_err || ' mort(s)', 'danger') || ' ' ELSE '' END
        || pgv.badge(v_ok || ' ok', 'success'))
      || '<md>' || chr(10)
      || '| Niveau | Source | Detail |' || chr(10)
      || '|--------|--------|--------|' || chr(10)
      || v_rows
      || '</md>' || chr(10);
  END IF;

  -- 10. Dead post_* functions (exist but never referenced by data-rpc or pgv.action)
  v_rows := '';
  v_warn := 0;
  FOR v_rec IN
    WITH rpc_refs AS (
      SELECT (regexp_matches(pg_get_functiondef(p.oid), 'data-rpc="([^"]+)"', 'g'))[1] AS rpc
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema
      UNION
      SELECT (regexp_matches(pg_get_functiondef(p.oid), E'pgv\\.action\\(''([^'']+)''', 'g'))[1] AS rpc
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema
    ),
    referenced AS (
      SELECT DISTINCT 'post_' || regexp_replace(
        CASE WHEN rpc LIKE '%.%' THEN split_part(rpc, '.', 2) ELSE rpc END,
        '^post_', ''
      ) AS fn
      FROM rpc_refs
    ),
    all_posts AS (
      SELECT p.proname
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema AND p.proname LIKE 'post_%'
    )
    SELECT a.proname
    FROM all_posts a
    WHERE a.proname NOT IN (SELECT fn FROM referenced)
    ORDER BY a.proname
  LOOP
    v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | ' || pgv.esc(v_rec.proname) || ' | aucun data-rpc ne reference cette fonction |' || chr(10);
    v_warn := v_warn + 1;
  END LOOP;

  IF v_warn > 0 THEN
    v_reports := v_reports || pgv.dl(
      'Dead code POST', p_schema,
      'Bilan', pgv.badge(v_warn || ' non-reference(s)', 'warning'))
      || '<md>' || chr(10)
      || '| Niveau | Fonction | Detail |' || chr(10)
      || '|--------|----------|--------|' || chr(10)
      || v_rows
      || '</md>' || chr(10);
  END IF;

  -- 11. i18n: hardcoded French strings (schema-wide)
  v_rows := '';
  v_warn := 0;
  v_ok := 0;

  FOR v_rec IN
    WITH fn_scan AS (
      SELECT p.proname, pg_get_functiondef(p.oid) AS def
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema
        AND (p.proname LIKE 'get_%' OR p.proname LIKE 'post_%'
             OR p.proname IN ('nav_items', 'brand'))
    )
    SELECT proname,
           def ~ '[éèêëàâùûôîïüçÉÈÊËÀÂÙÛÔÎÏÜÇ]' AS has_fr,
           def LIKE '%pgv.t(%' AS has_t,
           CASE WHEN def ~ '[éèêëàâùûôîïüçÉÈÊËÀÂÙÛÔÎÏÜÇ]' AND NOT def LIKE '%pgv.t(%' THEN
             (regexp_match(def, '''([^'']*[éèêëàâùûôîïüçÉÈÊËÀÂÙÛÔÎÏÜÇ][^'']*)'''))[1]
           END AS sample
    FROM fn_scan
    ORDER BY proname
  LOOP
    IF v_rec.has_fr AND NOT v_rec.has_t THEN
      v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | ' || v_rec.proname || '() | `' || pgv.esc(coalesce(substr(v_rec.sample, 1, 50), '?')) || '` |' || chr(10);
      v_warn := v_warn + 1;
    ELSE
      v_ok := v_ok + 1;
    END IF;
  END LOOP;

  IF v_warn > 0 OR v_ok > 0 THEN
    v_reports := v_reports || pgv.dl(
      'i18n', p_schema,
      'Bilan',
        CASE WHEN v_warn > 0 THEN pgv.badge(v_warn || ' fonction(s) FR', 'warning') || ' ' ELSE '' END
        || CASE WHEN v_ok > 0 THEN pgv.badge(v_ok || ' ok', 'success') ELSE '' END)
      || '<md>' || chr(10)
      || '| Niveau | Source | Detail |' || chr(10)
      || '|--------|--------|--------|' || chr(10)
      || v_rows
      || '</md>' || chr(10);
  END IF;

  -- 12. HTML audit: raw HTML that should use pgv.* primitives (schema-wide)
  v_reports := v_reports || pgv.html_audit(p_schema);

  RETURN v_reports;
END;
$function$;
COMMENT ON FUNCTION pgv.diagnose(text,text) IS 'Diagnose a pgView page: render + check contract (styles, HTMX, RPCs, links, md, forms). Use * for all pages.';

CREATE OR REPLACE FUNCTION pgv.rsql_to_where(p_filter text, p_schema text, p_table text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_or_parts text[];
  v_or_part text;
  v_and_parts text[];
  v_and_part text;
  v_or_clauses text[] := '{}';
  v_and_clauses text[];
  v_field text;
  v_op text;
  v_val text;
  v_col text;
  v_col_type text;
  v_sql_part text;
  v_match text[];
  v_is_numeric boolean;
  v_path text[];
  v_jsonb_path text;
  v_fk_target_schema text;
  v_fk_target_table text;
  v_fk_src_col text;
  v_fk_tgt_col text;
  v_fk_filter_col text;
  v_fk_col_type text;
BEGIN
  IF p_filter IS NULL OR trim(p_filter) = '' THEN
    RETURN 'true';
  END IF;

  v_val := p_filter;
  WHILE v_val ~ '\([^)]*,[^)]*\)' LOOP
    v_val := regexp_replace(v_val, '\(([^)]*),([^)]*)\)', '(\1' || chr(1) || '\2)', 'g');
  END LOOP;

  v_or_parts := string_to_array(v_val, ',');

  FOREACH v_or_part IN ARRAY v_or_parts LOOP
    v_and_clauses := '{}';
    v_and_parts := string_to_array(v_or_part, ';');

    FOREACH v_and_part IN ARRAY v_and_parts LOOP
      v_match := regexp_match(v_and_part, '^([a-zA-Z_][a-zA-Z0-9_.]*)(==|!=|>=|<=|>|<|=in=|=out=|=like=|=ilike=|=isnull=|=notnull=|=bt=)(.+)$');

      IF v_match IS NULL THEN
        RAISE EXCEPTION 'rsql: invalid expression "%"', v_and_part;
      END IF;

      v_field := v_match[1];
      v_op := v_match[2];
      v_val := replace(v_match[3], chr(1), ',');

      v_path := string_to_array(v_field, '.');
      v_col := v_path[1];

      -- Look up column type
      SELECT t.typname INTO v_col_type
      FROM pg_attribute a
      JOIN pg_class c ON c.oid = a.attrelid
      JOIN pg_namespace n ON n.oid = c.relnamespace
      JOIN pg_type t ON t.oid = a.atttypid
      WHERE n.nspname = p_schema AND c.relname = p_table
        AND a.attname = v_col AND a.attnum > 0 AND NOT a.attisdropped;

      -- v3: FK relation traversal (first segment = related table name)
      IF v_col_type IS NULL AND array_length(v_path, 1) > 1 THEN
        SELECT n2.nspname, c2.relname, a1.attname, a2.attname
        INTO v_fk_target_schema, v_fk_target_table, v_fk_src_col, v_fk_tgt_col
        FROM pg_constraint con
        JOIN pg_class c1 ON c1.oid = con.conrelid
        JOIN pg_namespace n1 ON n1.oid = c1.relnamespace
        JOIN pg_class c2 ON c2.oid = con.confrelid
        JOIN pg_namespace n2 ON n2.oid = c2.relnamespace
        JOIN pg_attribute a1 ON a1.attrelid = con.conrelid AND a1.attnum = con.conkey[1]
        JOIN pg_attribute a2 ON a2.attrelid = con.confrelid AND a2.attnum = con.confkey[1]
        WHERE con.contype = 'f'
          AND n1.nspname = p_schema AND c1.relname = p_table
          AND c2.relname = v_col;

        IF v_fk_target_schema IS NULL THEN
          RAISE EXCEPTION 'rsql: "%" is not a column or FK relation in %.%', v_col, p_schema, p_table;
        END IF;

        v_fk_filter_col := v_path[2];
        SELECT t.typname INTO v_fk_col_type
        FROM pg_attribute a
        JOIN pg_class c ON c.oid = a.attrelid
        JOIN pg_namespace n ON n.oid = c.relnamespace
        JOIN pg_type t ON t.oid = a.atttypid
        WHERE n.nspname = v_fk_target_schema AND c.relname = v_fk_target_table
          AND a.attname = v_fk_filter_col AND a.attnum > 0 AND NOT a.attisdropped;

        IF v_fk_col_type IS NULL THEN
          RAISE EXCEPTION 'rsql: column "%" does not exist in %.%', v_fk_filter_col, v_fk_target_schema, v_fk_target_table;
        END IF;

        v_is_numeric := v_fk_col_type IN ('int2', 'int4', 'int8', 'float4', 'float8', 'numeric');
        v_sql_part := pgv._rsql_compare(format('%I', v_fk_filter_col), v_op, v_val, v_is_numeric, v_fk_col_type);
        v_sql_part := format('EXISTS (SELECT 1 FROM %I.%I WHERE %I = %I.%I AND %s)',
          v_fk_target_schema, v_fk_target_table,
          v_fk_tgt_col, p_table, v_fk_src_col, v_sql_part);

        v_and_clauses := v_and_clauses || v_sql_part;
        CONTINUE;
      END IF;

      IF v_col_type IS NULL THEN
        RAISE EXCEPTION 'rsql: column "%" does not exist in %.%', v_col, p_schema, p_table;
      END IF;

      -- v2: JSONB traversal
      IF array_length(v_path, 1) > 1 AND v_col_type = 'jsonb' THEN
        v_jsonb_path := format('%I', v_col);
        FOR i IN 2..array_length(v_path, 1) LOOP
          IF i = array_length(v_path, 1) THEN
            IF v_path[i] ~ '^\d+$' THEN
              v_jsonb_path := v_jsonb_path || '->>' || v_path[i];
            ELSE
              v_jsonb_path := v_jsonb_path || '->>''' || v_path[i] || '''';
            END IF;
          ELSE
            IF v_path[i] ~ '^\d+$' THEN
              v_jsonb_path := v_jsonb_path || '->' || v_path[i];
            ELSE
              v_jsonb_path := v_jsonb_path || '->''' || v_path[i] || '''';
            END IF;
          END IF;
        END LOOP;

        v_sql_part := pgv._rsql_compare(v_jsonb_path, v_op, v_val, false, 'text');
        v_and_clauses := v_and_clauses || v_sql_part;
        CONTINUE;
      END IF;

      -- Simple column
      v_is_numeric := v_col_type IN ('int2', 'int4', 'int8', 'float4', 'float8', 'numeric');
      v_sql_part := pgv._rsql_compare(format('%I', v_col), v_op, v_val, v_is_numeric, v_col_type);
      v_and_clauses := v_and_clauses || v_sql_part;
    END LOOP;

    v_or_clauses := v_or_clauses || ('(' || array_to_string(v_and_clauses, ' AND ') || ')');
  END LOOP;

  IF array_length(v_or_clauses, 1) = 1 THEN
    RETURN substr(v_or_clauses[1], 2, length(v_or_clauses[1]) - 2);
  END IF;

  RETURN array_to_string(v_or_clauses, ' OR ');
END;
$function$;
COMMENT ON FUNCTION pgv.rsql_to_where(text,text,text) IS 'Parse RSQL filter into safe SQL WHERE. Supports jsonb dot notation (v2) and FK relation traversal (v3).';

CREATE OR REPLACE FUNCTION pgv.rsql_validate(p_filter text)
 RETURNS boolean
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_filter text;
  v_parts text[];
  v_part text;
  v_atoms text[];
  v_atom text;
BEGIN
  IF p_filter IS NULL OR trim(p_filter) = '' THEN
    RETURN true;
  END IF;

  -- Protect commas inside parentheses
  v_filter := p_filter;
  WHILE v_filter ~ '\([^)]*,[^)]*\)' LOOP
    v_filter := regexp_replace(v_filter, '\(([^)]*),([^)]*)\)', '(\1' || chr(1) || '\2)', 'g');
  END LOOP;

  -- Split by , (OR)
  v_parts := string_to_array(v_filter, ',');

  FOREACH v_part IN ARRAY v_parts LOOP
    -- Split by ; (AND)
    v_atoms := string_to_array(v_part, ';');
    FOREACH v_atom IN ARRAY v_atoms LOOP
      IF NOT v_atom ~ '^[a-zA-Z_][a-zA-Z0-9_]*(==|!=|>=|<=|>|<|=in=|=out=|=like=|=ilike=|=isnull=|=notnull=|=bt=).+$' THEN
        RETURN false;
      END IF;
    END LOOP;
  END LOOP;

  RETURN true;
END;
$function$;
COMMENT ON FUNCTION pgv.rsql_validate(text) IS 'Validate RSQL filter syntax without executing. Returns true if valid, false otherwise.';

CREATE OR REPLACE FUNCTION pgv.schema_catalog()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT coalesce(jsonb_agg(row ORDER BY row->>'schema'), '[]')
  FROM (
    SELECT jsonb_build_object(
      'schema', n.nspname,
      'comment', d.description,
      'tables', (
        SELECT count(*) FROM pg_class c
        WHERE c.relnamespace = n.oid AND c.relkind = 'r'
      ),
      'functions', (
        SELECT count(*) FROM pg_proc p
        WHERE p.pronamespace = n.oid
      )
    ) AS row
    FROM pg_namespace n
    LEFT JOIN pg_description d ON d.objoid = n.oid AND d.classoid = 'pg_namespace'::regclass
    WHERE n.nspname NOT LIKE 'pg_%'
      AND n.nspname NOT IN ('information_schema', 'public', 'extensions')
      AND n.nspname NOT LIKE '%_ut'
      AND n.nspname NOT LIKE '%_qa'
      AND n.nspname NOT LIKE '%_it'
  ) sub;
$function$;
COMMENT ON FUNCTION pgv.schema_catalog() IS 'Returns overview of all application schemas: name, table count, function count, comment. Excludes system/test/qa schemas.';

CREATE OR REPLACE FUNCTION pgv.schema_comments(p_schema text)
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  WITH schema_comment AS (
    SELECT 'SCHEMA ' || p_schema || ': ' || coalesce(d.description, '(none)')
    FROM pg_namespace n
    LEFT JOIN pg_description d ON d.objoid = n.oid AND d.classoid = 'pg_namespace'::regclass
    WHERE n.nspname = p_schema
  ),
  table_comments AS (
    SELECT c.relname AS tbl,
           d.description AS tbl_comment,
           a.attname AS col,
           cd.description AS col_comment
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    LEFT JOIN pg_description d ON d.objoid = c.oid AND d.objsubid = 0
    LEFT JOIN pg_attribute a ON a.attrelid = c.oid AND a.attnum > 0 AND NOT a.attisdropped
    LEFT JOIN pg_description cd ON cd.objoid = c.oid AND cd.objsubid = a.attnum
    WHERE n.nspname = p_schema AND c.relkind = 'r'
    ORDER BY c.relname, a.attnum
  ),
  formatted AS (
    SELECT string_agg(line, chr(10)) AS body
    FROM (
      SELECT '## ' || tbl
        || chr(10) || 'table: ' || coalesce(tbl_comment, '(no comment)')
        || chr(10) || string_agg(
          '  ' || col || ': ' || coalesce(col_comment, '-'),
          chr(10) ORDER BY col
        ) AS line
      FROM table_comments
      GROUP BY tbl, tbl_comment
      ORDER BY tbl
    ) sub
  )
  SELECT (SELECT * FROM schema_comment) || chr(10) || chr(10) || coalesce(f.body, '(no tables)')
  FROM formatted f;
$function$;
COMMENT ON FUNCTION pgv.schema_comments(text) IS 'Lists all COMMENT ON for a schema (tables + columns). Text format for coverage review.';

CREATE OR REPLACE FUNCTION pgv.schema_discover(p_schema text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT coalesce(jsonb_agg(tbl ORDER BY tbl->>'table'), '[]')
  FROM (
    SELECT jsonb_build_object(
      'table', c.relname,
      'comment', d.description,
      'rows', c.reltuples::bigint,
      'columns', (
        SELECT coalesce(jsonb_agg(
          jsonb_build_object(
            'name', col.column_name,
            'type', col.udt_name || CASE
              WHEN col.character_maximum_length IS NOT NULL THEN '(' || col.character_maximum_length || ')'
              ELSE '' END,
            'nullable', col.is_nullable = 'YES',
            'default', col.column_default,
            'comment', cd.description
          ) ORDER BY col.ordinal_position
        ), '[]')
        FROM information_schema.columns col
        LEFT JOIN pg_attribute a ON a.attrelid = c.oid AND a.attname = col.column_name::name
        LEFT JOIN pg_description cd ON cd.objoid = c.oid AND cd.objsubid = a.attnum
        WHERE col.table_schema = p_schema AND col.table_name = c.relname
      ),
      'foreign_keys', (
        SELECT coalesce(jsonb_agg(
          jsonb_build_object(
            'column', kcu.column_name,
            'references', ccu.table_schema || '.' || ccu.table_name || '.' || ccu.column_name
          )
        ), '[]')
        FROM information_schema.table_constraints tc
        JOIN information_schema.key_column_usage kcu
          ON kcu.constraint_name = tc.constraint_name AND kcu.table_schema = tc.table_schema
        JOIN information_schema.constraint_column_usage ccu
          ON ccu.constraint_name = tc.constraint_name AND ccu.constraint_schema = tc.constraint_schema
        WHERE tc.table_schema = p_schema AND tc.table_name = c.relname
          AND tc.constraint_type = 'FOREIGN KEY'
      )
    ) AS tbl
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    LEFT JOIN pg_description d ON d.objoid = c.oid AND d.objsubid = 0
    WHERE n.nspname = p_schema AND c.relkind = 'r'
  ) sub;
$function$;
COMMENT ON FUNCTION pgv.schema_discover(text) IS 'Returns complete schema structure: tables with columns, FK relations, comments, row counts.';

CREATE OR REPLACE FUNCTION pgv.schema_table(p_schema text, p_table text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_object(
    'schema', p_schema,
    'table', p_table,
    'comment', (
      SELECT d.description FROM pg_description d
      JOIN pg_class c ON c.oid = d.objoid
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname = p_schema AND c.relname = p_table AND d.objsubid = 0
    ),
    'columns', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'name', col.column_name,
          'type', col.udt_name || CASE
            WHEN col.character_maximum_length IS NOT NULL THEN '(' || col.character_maximum_length || ')'
            ELSE '' END,
          'nullable', col.is_nullable = 'YES',
          'default', col.column_default,
          'comment', (
            SELECT d.description FROM pg_description d
            JOIN pg_class c ON c.oid = d.objoid
            JOIN pg_namespace n ON n.oid = c.relnamespace
            JOIN pg_attribute a ON a.attrelid = c.oid AND a.attnum = d.objsubid
            WHERE n.nspname = p_schema AND c.relname = p_table AND a.attname = col.column_name::name
          )
        ) ORDER BY col.ordinal_position
      ), '[]')
      FROM information_schema.columns col
      WHERE col.table_schema = p_schema AND col.table_name = p_table
    ),
    'check_constraints', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'name', cc.constraint_name,
          'definition', cc.check_clause
        )
      ), '[]')
      FROM information_schema.check_constraints cc
      JOIN information_schema.table_constraints tc
        ON tc.constraint_name = cc.constraint_name AND tc.constraint_schema = cc.constraint_schema
      WHERE tc.table_schema = p_schema AND tc.table_name = p_table
        AND tc.constraint_type = 'CHECK'
        AND cc.check_clause NOT LIKE '%IS NOT NULL%'
    ),
    'foreign_keys', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'column', kcu.column_name,
          'references', ccu.table_schema || '.' || ccu.table_name || '.' || ccu.column_name
        )
      ), '[]')
      FROM information_schema.table_constraints tc
      JOIN information_schema.key_column_usage kcu
        ON kcu.constraint_name = tc.constraint_name AND kcu.table_schema = tc.table_schema
      JOIN information_schema.constraint_column_usage ccu
        ON ccu.constraint_name = tc.constraint_name AND ccu.constraint_schema = tc.constraint_schema
      WHERE tc.table_schema = p_schema AND tc.table_name = p_table
        AND tc.constraint_type = 'FOREIGN KEY'
    ),
    'indexes', (
      SELECT coalesce(jsonb_agg(
        jsonb_build_object(
          'name', i.relname,
          'unique', ix.indisunique,
          'columns', (
            SELECT jsonb_agg(a.attname ORDER BY k.ord)
            FROM unnest(ix.indkey) WITH ORDINALITY AS k(attnum, ord)
            JOIN pg_attribute a ON a.attrelid = ix.indrelid AND a.attnum = k.attnum
          )
        )
      ), '[]')
      FROM pg_index ix
      JOIN pg_class t ON t.oid = ix.indrelid
      JOIN pg_class i ON i.oid = ix.indexrelid
      JOIN pg_namespace n ON n.oid = t.relnamespace
      WHERE n.nspname = p_schema AND t.relname = p_table
        AND NOT ix.indisprimary
    ),
    'rls', (
      SELECT jsonb_build_object(
        'enabled', c.relrowsecurity,
        'policies', coalesce((
          SELECT jsonb_agg(jsonb_build_object('name', pol.polname, 'permissive', pol.polpermissive))
          FROM pg_policy pol WHERE pol.polrelid = c.oid
        ), '[]')
      )
      FROM pg_class c
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname = p_schema AND c.relname = p_table
    )
  );
$function$;
COMMENT ON FUNCTION pgv.schema_table(text,text) IS 'Returns detailed table structure: columns, CHECK constraints, FK, indexes, RLS policies.';

CREATE OR REPLACE FUNCTION pgv.script(p_js text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<script>' || p_js || '</script>';
$function$;

CREATE OR REPLACE FUNCTION pgv.search_item(p_result pgv.search_result)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<li class="pgv-search-item" data-href="' || pgv.esc(p_result.href) || '">'
    || CASE WHEN p_result.icon IS NOT NULL THEN '<span class="pgv-search-icon">' || p_result.icon || '</span> ' ELSE '' END
    || '<span class="pgv-search-body">'
    || '<strong>' || pgv.esc(p_result.label) || '</strong>'
    || CASE WHEN p_result.kind IS NOT NULL THEN ' ' || pgv.badge(p_result.kind) ELSE '' END
    || CASE WHEN p_result.detail IS NOT NULL THEN '<small>' || pgv.esc(p_result.detail) || '</small>' ELSE '' END
    || '</span>'
    || '</li>';
$function$;
COMMENT ON FUNCTION pgv.search_item(pgv.search_result) IS 'Render a single search result as an HTML list item with data-href for shell navigation.';

CREATE OR REPLACE FUNCTION pgv.search(p_query text, p_schema text, p_limit integer DEFAULT 12, p_offset integer DEFAULT 0)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  v_results pgv.search_result[];
  v_r pgv.search_result;
  v_html text := '';
  v_count int := 0;
  v_total int := 0;
BEGIN
  -- Check module has a search provider
  IF NOT EXISTS (
    SELECT 1 FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = p_schema AND p.proname = 'search'
  ) THEN
    RETURN '<div class="pgv-empty"><h4>Recherche non disponible</h4><p>Le module ' || pgv.esc(p_schema) || ' n''a pas de fonction search().</p></div>';
  END IF;

  -- Call module search provider
  EXECUTE format(
    'SELECT array_agg(r ORDER BY r.score DESC) FROM %I.search($1, $2, $3) r',
    p_schema
  ) USING p_query, p_limit + 1, p_offset
  INTO v_results;

  IF v_results IS NULL OR array_length(v_results, 1) = 0 THEN
    RETURN '<div class="pgv-empty"><h4>Aucun resultat</h4><p>Aucune entite ne correspond a "' || pgv.esc(p_query) || '".</p></div>';
  END IF;

  v_total := array_length(v_results, 1);

  -- Render results (limit to p_limit, use +1 to detect hasMore)
  v_html := '<ul class="pgv-search-results">';
  FOREACH v_r IN ARRAY v_results LOOP
    v_count := v_count + 1;
    IF v_count > p_limit THEN EXIT; END IF;
    v_html := v_html || pgv.search_item(v_r);
  END LOOP;
  v_html := v_html || '</ul>';

  -- Has more indicator
  IF v_total > p_limit THEN
    v_html := v_html || '<div class="pgv-search-more" data-offset="' || (p_offset + p_limit) || '">...</div>';
  END IF;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.search(text,text,integer,integer) IS 'Search dispatcher: calls {schema}.search() convention, renders results as HTML. Returns empty state if no results.';

CREATE OR REPLACE FUNCTION pgv.sel(p_name text, p_label text, p_options jsonb, p_selected text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_html text; v_opt jsonb; v_val text; v_lbl text;
BEGIN
  v_html := '<label>' || p_label || '<select name="' || p_name || '">';
  v_html := v_html || '<option value="">--</option>';
  FOR v_opt IN SELECT * FROM jsonb_array_elements(p_options) LOOP
    IF jsonb_typeof(v_opt) = 'string' THEN
      v_val := v_opt #>> '{}'; v_lbl := v_val;
    ELSE
      v_val := v_opt->>'value'; v_lbl := coalesce(v_opt->>'label', v_val);
    END IF;
    v_html := v_html || '<option value="' || pgv.esc(v_val) || '"'
      || CASE WHEN v_val = p_selected THEN ' selected' ELSE '' END
      || '>' || pgv.esc(v_lbl) || '</option>';
  END LOOP;
  RETURN v_html || '</select></label>';
END;
$function$;

CREATE OR REPLACE FUNCTION pgv.select_search(p_name text, p_label text, p_rpc text, p_placeholder text DEFAULT ''::text, p_value text DEFAULT NULL::text, p_display text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN '<label>' || pgv.esc(p_label)
    || '<div class="pgv-ss" data-ss-rpc="' || pgv.esc(p_rpc) || '">'
    || '<input type="text" class="pgv-ss-input"'
    || ' placeholder="' || pgv.esc(coalesce(p_placeholder, '')) || '"'
    || CASE WHEN p_display IS NOT NULL THEN ' value="' || pgv.esc(p_display) || '"' ELSE '' END
    || ' autocomplete="off">'
    || '<input type="hidden" name="' || pgv.esc(p_name) || '"'
    || CASE WHEN p_value IS NOT NULL THEN ' value="' || pgv.esc(p_value) || '"' ELSE '' END
    || '>'
    || '<div class="pgv-ss-results"></div>'
    || '</div></label>';
END;
$function$;
COMMENT ON FUNCTION pgv.select_search(text,text,text,text,text,text) IS 'Search-select combo: text input + hidden value + async dropdown fetched from RPC. Uses pgv-ss-* classes.';

CREATE OR REPLACE FUNCTION pgv.stat(p_label text, p_value text, p_detail text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<article class="pgv-stat">'
    || '<small>' || pgv.esc(p_label) || '</small>'
    || '<p class="pgv-stat-value">' || p_value || '</p>'
    || CASE WHEN p_detail IS NOT NULL THEN '<small>' || pgv.esc(p_detail) || '</small>' ELSE '' END
    || '</article>';
$function$;

CREATE OR REPLACE FUNCTION pgv.t(p_key text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_lang text;
  v_value text;
BEGIN
  v_lang := coalesce(nullif(current_setting('pgv.lang', true), ''), 'fr');

  SELECT value INTO v_value FROM pgv.i18n WHERE lang = v_lang AND key = p_key;
  IF FOUND THEN RETURN v_value; END IF;

  -- Fallback to French if different lang
  IF v_lang <> 'fr' THEN
    SELECT value INTO v_value FROM pgv.i18n WHERE lang = 'fr' AND key = p_key;
    IF FOUND THEN RETURN v_value; END IF;
  END IF;

  -- Return key itself as last resort
  RETURN p_key;
END;
$function$;
COMMENT ON FUNCTION pgv.t(text) IS 'i18n translation lookup. Returns translated value or the key itself as fallback.';

CREATE OR REPLACE FUNCTION pgv.filter_form(p_body text, p_submit text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN '<div class="pgv-filter">'
    || '<form data-filter class="pgv-filter-bar">'
    || '<div class="pgv-filter-inputs">'
    || p_body
    || '</div>'
    || '<button type="submit" class="pgv-filter-submit">'
    || pgv.esc(coalesce(p_submit, pgv.t('pgv.filter')))
    || '</button>'
    || '</form>'
    || '<div class="pgv-filter-chips"></div>'
    || '</div>';
END;
$function$;
COMMENT ON FUNCTION pgv.filter_form(text,text) IS 'Inline filter bar: wraps inputs in compact flex row with submit button and chips container. GET-based (data-filter), shell handles SPA navigation + active filter chips.';

CREATE OR REPLACE FUNCTION pgv.form(p_rpc text, p_body text, p_submit text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN '<form data-rpc="' || pgv.esc(p_rpc) || '">'
    || p_body
    || '<button type="submit">' || pgv.esc(coalesce(p_submit, pgv.t('send'))) || '</button>'
    || '</form>';
END;
$function$;
COMMENT ON FUNCTION pgv.form(text,text,text) IS 'Form wrapper with data-rpc dispatch. Wraps body in form tag with submit button.';

CREATE OR REPLACE FUNCTION pgv.form_dialog(p_id text, p_title text, p_body text, p_rpc text, p_label text DEFAULT NULL::text, p_variant text DEFAULT NULL::text, p_src text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_trigger text;
  v_dialog text;
  v_btn_class text;
BEGIN
  -- Trigger button
  v_btn_class := CASE
    WHEN p_variant = 'outline' THEN ' class="outline"'
    WHEN p_variant = 'secondary' THEN ' class="secondary"'
    WHEN p_variant = 'contrast' THEN ' class="contrast"'
    ELSE ''
  END;

  v_trigger := '<button data-form-dialog="' || pgv.esc(p_id) || '"'
    || CASE WHEN p_src IS NOT NULL THEN ' data-src="' || pgv.esc(p_src) || '"' ELSE '' END
    || v_btn_class
    || '>' || pgv.esc(coalesce(p_label, p_title)) || '</button>';

  -- Dialog element
  v_dialog := '<dialog id="' || pgv.esc(p_id) || '" class="pgv-form-dialog">'
    || '<article class="pgv-form-dialog-article">'
    || '<header class="pgv-form-dialog-header">'
    || '<strong>' || pgv.esc(p_title) || '</strong>'
    || '<button class="pgv-form-dialog-close" onclick="this.closest(''dialog'').close()">&times;</button>'
    || '</header>'
    || '<form data-rpc="' || pgv.esc(p_rpc) || '" data-dialog-form>'
    || '<div class="pgv-form-dialog-body">' || p_body || '</div>'
    || '<footer class="pgv-form-dialog-footer">'
    || '<button type="button" class="secondary" onclick="this.closest(''dialog'').close()">'
    || pgv.t('cancel') || '</button>'
    || '<button type="submit">' || pgv.t('send') || '</button>'
    || '</footer>'
    || '</form>'
    || '</article>'
    || '</dialog>';

  RETURN v_trigger || v_dialog;
END;
$function$;
COMMENT ON FUNCTION pgv.form_dialog(text,text,text,text,text,text,text) IS 'Render a button that opens a modal dialog containing a form. Supports create (inline body) and edit (lazy-load via data-src). On submit success: toast + close + reload.';

CREATE OR REPLACE FUNCTION pgv.svg_canvas(p_svg text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_id text := 'sc_' || substr(md5(random()::text), 1, 8);
  v_height text := coalesce(p_options->>'height', '60vh');
  v_toolbar boolean := coalesce((p_options->>'toolbar')::boolean, true);
  v_html text;
  v_js text;
BEGIN
  IF p_svg IS NULL OR p_svg = '' THEN RETURN ''; END IF;

  v_html := '<div class="pgv-canvas" id="' || v_id || '">'
    || '<div class="pgv-canvas-vp" id="' || v_id || '_vp" data-height="' || pgv.esc(v_height) || '">'
    || p_svg
    || '</div>';

  IF v_toolbar THEN
    v_html := v_html
      || '<div class="pgv-canvas-bar">'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_out" title="Zoom out">&minus;</button>'
      || '<span class="pgv-canvas-zoom" id="' || v_id || '_zl">100%</span>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_in" title="Zoom in">+</button>'
      || '<span class="pgv-canvas-sep"></span>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_fit" title="Ajuster">Fit</button>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_reset" title="1:1">1:1</button>'
      || '<span class="pgv-canvas-sep"></span>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_print" title="' || pgv.t('pgv.print') || '">&#x1F5B6;</button>'
      || '</div>';
  END IF;

  IF NOT v_toolbar THEN
    v_html := v_html
      || '<button class="pgv-print-btn" id="' || v_id || '_print2" title="' || pgv.t('pgv.print') || '">&#x1F5B6;</button>';
  END IF;

  v_html := v_html || '</div>';

  v_js := $JS$
(function(){
  var id="__ID__",
      vp=document.getElementById(id+"_vp"),
      svg=vp&&vp.querySelector("svg"),
      zl=document.getElementById(id+"_zl");
  if(!vp||!svg||typeof panzoom==="undefined")return;
  if(vp.dataset.height)vp.style.height=vp.dataset.height;
  var pz=panzoom(svg,{maxZoom:20,minZoom:0.05,smoothScroll:false,bounds:true,boundsPadding:0.2});
  function upd(){if(zl)zl.textContent=Math.round(pz.getTransform().scale*100)+"%";}
  pz.on("zoom",upd);
  pz.on("transform",upd);
  var zi=document.getElementById(id+"_in"),
      zo=document.getElementById(id+"_out"),
      fb=document.getElementById(id+"_fit"),
      rb=document.getElementById(id+"_reset");
  if(zi)zi.onclick=function(){pz.smoothZoom(vp.clientWidth/2,vp.clientHeight/2,1.3);};
  if(zo)zo.onclick=function(){pz.smoothZoom(vp.clientWidth/2,vp.clientHeight/2,0.7);};
  if(rb)rb.onclick=function(){pz.moveTo(0,0);pz.zoomAbs(0,0,1);upd();};
  if(fb)fb.onclick=function(){
    var bb=svg.getBBox(),vw=vp.clientWidth,vh=vp.clientHeight,
        sc=Math.min(vw/(bb.width+bb.x*2),vh/(bb.height+bb.y*2))*0.9,
        ox=(vw-bb.width*sc)/2-bb.x*sc,
        oy=(vh-bb.height*sc)/2-bb.y*sc;
    pz.zoomAbs(0,0,sc);pz.moveTo(ox,oy);upd();
  };
  if(fb){if(vp.clientWidth>0)fb.onclick();else{var io=new IntersectionObserver(function(es){if(es[0].isIntersecting&&vp.clientWidth>0){fb.onclick();io.disconnect();}});io.observe(vp);}}
  var pb=document.getElementById(id+"_print")||document.getElementById(id+"_print2");
  if(pb)pb.onclick=function(){var s=vp.querySelector("svg");if(!s)return;var c=s.cloneNode(true);c.removeAttribute("style");var bb=s.getBBox();var pad=10;c.setAttribute("viewBox",(bb.x-pad)+" "+(bb.y-pad)+" "+(bb.width+pad*2)+" "+(bb.height+pad*2));c.setAttribute("width",bb.width+pad*2);c.setAttribute("height",bb.height+pad*2);c.setAttribute("xmlns","http://www.w3.org/2000/svg");c.setAttribute("xmlns:xlink","http://www.w3.org/1999/xlink");var imgs=c.querySelectorAll("image");if(!imgs.length){var bl=new Blob([c.outerHTML],{type:"image/svg+xml"});var al=document.createElement("a");al.href=URL.createObjectURL(bl);al.download="export.svg";al.click();URL.revokeObjectURL(al.href);return;}var done=0;imgs.forEach(function(img){var url=img.getAttribute("href")||img.getAttributeNS("http://www.w3.org/1999/xlink","href");if(!url||url.startsWith("data:")){done++;if(done===imgs.length)dl();return;}fetch(url).then(function(r){return r.blob();}).then(function(blob){var rd=new FileReader();rd.onload=function(){img.setAttribute("href",rd.result);img.removeAttributeNS("http://www.w3.org/1999/xlink","href");done++;if(done===imgs.length)dl();};rd.readAsDataURL(blob);}).catch(function(){done++;if(done===imgs.length)dl();});});function dl(){var bl=new Blob([c.outerHTML],{type:"image/svg+xml"});var al=document.createElement("a");al.href=URL.createObjectURL(bl);al.download="export.svg";al.click();URL.revokeObjectURL(al.href);}};
})();
$JS$;

  v_js := replace(v_js, '__ID__', v_id);
  v_html := v_html || pgv.script(v_js);

  RETURN v_html;
END;
$function$;

CREATE OR REPLACE FUNCTION pgv."table"(p_config jsonb)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  RETURN '<div x-data="pgvTable" data-config="' || pgv.esc(p_config::text) || '"></div>';
END;
$function$;
COMMENT ON FUNCTION pgv."table"(jsonb) IS 'Declarative table with filters, pagination, and sorting. Generates Alpine pgvTable placeholder from JSON config.';

CREATE OR REPLACE FUNCTION pgv.tabs(VARIADIC p_items text[])
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_count int := array_length(p_items, 1) / 2;
  v_nav text := '';
  v_panels text := '';
BEGIN
  FOR i IN 0..v_count-1 LOOP
    v_nav := v_nav || '<button @click="tab=' || i || '" :class="tab===' || i || ' && ''active''">'
      || pgv.esc(p_items[i*2+1]) || '</button>';
    v_panels := v_panels || '<div x-show="tab===' || i || '">' || p_items[i*2+2] || '</div>';
  END LOOP;
  RETURN '<div class="pgv-tabs" x-data="{tab:0}">'
    || '<nav class="pgv-tabs-nav">' || v_nav || '</nav>'
    || v_panels || '</div>';
END;
$function$;
COMMENT ON FUNCTION pgv.tabs(text[]) IS 'Tabbed panels with Alpine.js state (VARIADIC label/content pairs)';

CREATE OR REPLACE FUNCTION pgv.textarea(p_name text, p_label text, p_value text DEFAULT NULL::text, p_rows integer DEFAULT 3)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<label>' || p_label
    || '<textarea name="' || p_name || '" rows="' || p_rows || '">'
    || coalesce(pgv.esc(p_value), '')
    || '</textarea></label>';
$function$;

CREATE OR REPLACE FUNCTION pgv.timeline(p_items jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text := '<div class="pgv-tl">';
  v_item jsonb;
  v_badge text;
  v_dot_cls text;
BEGIN
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP
    v_badge := coalesce(v_item->>'badge', '');
    v_dot_cls := 'pgv-tl-dot' || CASE WHEN v_badge <> '' THEN ' pgv-tl-dot-' || v_badge ELSE '' END;

    v_html := v_html || '<div class="pgv-tl-item">'
      || '<span class="' || v_dot_cls || '"></span>';

    IF v_item->>'date' IS NOT NULL THEN
      v_html := v_html || '<div class="pgv-tl-date">' || pgv.esc(v_item->>'date') || '</div>';
    END IF;

    v_html := v_html || '<div class="pgv-tl-label">' || pgv.esc(v_item->>'label') || '</div>';

    IF v_item->>'detail' IS NOT NULL THEN
      v_html := v_html || '<div class="pgv-tl-detail">' || pgv.esc(v_item->>'detail') || '</div>';
    END IF;

    v_html := v_html || '</div>';
  END LOOP;

  RETURN v_html || '</div>';
END;
$function$;
COMMENT ON FUNCTION pgv.timeline(jsonb) IS 'Vertical timeline with dated entries, optional badge colors (success/danger/warning/info/primary)';

CREATE OR REPLACE FUNCTION pgv.toast(p_message text, p_level text DEFAULT 'success'::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN '<template data-toast="' || pgv.esc(p_level) || '">' || pgv.esc(p_message) || '</template>';
END;
$function$;
COMMENT ON FUNCTION pgv.toast(text,text) IS 'POST response: toast notification. Returns template tag for Alpine shell.';

CREATE OR REPLACE FUNCTION pgv.post_issue_report(p jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_desc text;
  v_type text;
  v_module text;
  v_ctx  jsonb;
BEGIN
  v_desc := trim(p->>'description');
  IF v_desc IS NULL OR v_desc = '' THEN
    RETURN pgv.toast(pgv.t('issue.error'), 'error');
  END IF;

  v_type := coalesce(p->>'issue_type', 'bug');
  IF v_type NOT IN ('bug', 'enhancement', 'question') THEN
    v_type := 'bug';
  END IF;

  v_module := p->>'schema';

  -- Build context from remaining keys
  v_ctx := p - 'description' - 'issue_type' - 'schema';

  INSERT INTO workbench.issue_report (description, issue_type, module, context)
  VALUES (v_desc, v_type, v_module, v_ctx);

  RETURN pgv.toast(pgv.t('issue.success'));
END;
$function$;
COMMENT ON FUNCTION pgv.post_issue_report(jsonb) IS 'Receive an issue report (bug/enhancement/question) from the shell UI and store it in workbench.issue_report';

CREATE OR REPLACE FUNCTION pgv.toggle(p_name text, p_label text, p_checked boolean DEFAULT false)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<label><input type="checkbox" name="' || p_name || '" role="switch"'
    || CASE WHEN p_checked THEN ' checked' ELSE '' END
    || '> ' || pgv.esc(p_label) || '</label>';
$function$;
COMMENT ON FUNCTION pgv.toggle(text,text,boolean) IS 'Switch on/off toggle (PicoCSS role=switch)';

CREATE OR REPLACE FUNCTION pgv.tree(p_items jsonb, p_open boolean DEFAULT false, p_depth integer DEFAULT 0, p_root_attrs text DEFAULT ''::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text;
  v_item jsonb;
  v_label text;
  v_href text;
  v_open boolean;
  v_icon text;
  v_badge text;
  v_action jsonb;
  v_attrs text;
  v_prefix text;
  v_suffix text;
  v_li_open text;
BEGIN
  IF p_depth = 0 THEN
    v_html := '<ul class="pgv-tree"' || CASE WHEN p_root_attrs <> '' THEN ' ' || p_root_attrs ELSE '' END || '>';
  ELSE
    v_html := '<ul>';
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP
    v_label := v_item->>'label';
    v_href := v_item->>'href';
    v_open := coalesce((v_item->>'open')::boolean, p_open);
    v_icon := v_item->>'icon';
    v_badge := v_item->>'badge';
    v_action := v_item->'action';
    v_attrs := coalesce(v_item->>'attrs', '');

    -- Build prefix (icon = raw HTML, caller is responsible for content)
    v_prefix := CASE WHEN v_icon IS NOT NULL THEN '<span class="pgv-tree-icon">' || v_icon || '</span> ' ELSE '' END;
    v_suffix := '';
    IF v_badge IS NOT NULL THEN
      v_suffix := v_suffix || ' ' || pgv.badge(v_badge);
    END IF;
    IF v_action IS NOT NULL THEN
      IF jsonb_typeof(v_action) = 'string' THEN
        -- Raw HTML string (e.g. Alpine button)
        v_suffix := v_suffix || ' ' || (v_action #>> '{}');
      ELSE
        -- Object -> pgv.action()
        v_suffix := v_suffix || ' ' || pgv.action(
          v_action->>'rpc',
          coalesce(v_action->>'label', v_action->>'rpc'),
          CASE WHEN v_action ? 'params' THEN v_action->'params' ELSE NULL END,
          v_action->>'confirm'
        );
      END IF;
    END IF;

    v_li_open := '<li' || CASE WHEN v_attrs <> '' THEN ' ' || v_attrs ELSE '' END || '>';

    IF v_item ? 'children' THEN
      v_html := v_html || v_li_open || '<details'
        || CASE WHEN v_open THEN ' open' ELSE '' END
        || '><summary>' || v_prefix || pgv.esc(v_label) || v_suffix || '</summary>'
        || pgv.tree(v_item->'children', p_open, p_depth + 1)
        || '</details></li>';
    ELSIF v_href IS NOT NULL THEN
      v_html := v_html || v_li_open || v_prefix || '<a href="' || v_href || '">' || pgv.esc(v_label) || '</a>' || v_suffix || '</li>';
    ELSE
      v_html := v_html || v_li_open || v_prefix || pgv.esc(v_label) || v_suffix || '</li>';
    END IF;
  END LOOP;

  v_html := v_html || '</ul>';
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.tree(jsonb,boolean,integer,text) IS 'Recursive treeview from jsonb array. Nodes: {label, href?, children?, open?, icon?, badge?, action?, attrs?}. icon=raw HTML, action=string(raw HTML) or object(pgv.action).';

CREATE OR REPLACE FUNCTION pgv.workflow(p_steps jsonb, p_current text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text := '<div class="pgv-wf">';
  v_step jsonb;
  v_key text;
  v_label text;
  v_found boolean := false;
  v_cls text;
  v_i int := 0;
  v_total int;
BEGIN
  v_total := jsonb_array_length(p_steps);
  FOR v_step IN SELECT * FROM jsonb_array_elements(p_steps) LOOP
    v_key := v_step->>'key';
    v_label := coalesce(v_step->>'label', v_key);
    v_i := v_i + 1;

    IF v_key = p_current THEN
      v_cls := 'pgv-wf-step pgv-wf-current';
      v_found := true;
    ELSIF NOT v_found THEN
      v_cls := 'pgv-wf-step pgv-wf-done';
    ELSE
      v_cls := 'pgv-wf-step pgv-wf-future';
    END IF;

    v_html := v_html || '<div class="' || v_cls || '">'
      || '<span class="pgv-wf-dot"></span>'
      || '<span class="pgv-wf-label">' || pgv.esc(v_label) || '</span>'
      || '</div>';

    IF v_i < v_total THEN
      v_html := v_html || '<div class="pgv-wf-line' 
        || CASE WHEN NOT v_found THEN ' pgv-wf-line-done' ELSE '' END
        || '"></div>';
    END IF;
  END LOOP;

  RETURN v_html || '</div>';
END;
$function$;
COMMENT ON FUNCTION pgv.workflow(jsonb,text) IS 'Horizontal workflow progress bar with steps, current highlight, done/future states';

GRANT USAGE ON SCHEMA pgv TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA pgv TO anon;
GRANT SELECT ON ALL TABLES IN SCHEMA pgv TO anon;
